text:
Assume lifetime \(T\sim\text{Exp}(\theta)\)
Let \(t_{(1)} &lt; \cdots &lt; t_{(r)}\) be the \(r\) smallest lifetimes observed from an experiment with \(n\;(\geq r)\) subjects
The joint distribution of \(t_{(1)}, \ldots, t_{(r)}\) \[\begin{align}
f_T(t_{(1)}, \ldots, t_{(r)}) &= \frac{n!}{(n-r)!}\Big[\prod_{i=1}^r(1/\theta)e^{-t_{(i)}/\theta}\Big]\Big[e^{-t_{(r)}/\theta}\Big]^{n-r} \notag \\[.3em]
& = \frac{n!}{(n-r)!} \;\big({1}/{\theta}\big)^r\;e^{-\frac{1}{\theta}\big[{\color{purple}\sum_{i=1}^r t_{(i)} + (n-r)t_{(r)}}\big]}\notag \\[.25em]
& = \frac{n!}{(n-r)!} \;\big({1}/{\theta})^r \;e^{-{\color{purple}T_0}/\theta}\label{joint-type2}
\end{align}\]



The log-likelihood function \[\begin{align}
\ell(\theta) &= -\frac{1}{\theta}\sum_it_{(i)} -r\log(\theta) - (1/\theta)(n-r)t_{(r)} +\text{Const.} \notag \\
& = -\frac{1}{\theta}\Big[\sum_{i=1}^r t_{(i)} + (n-r) t_{(r)} \Big]
-r\log(\theta)+ \text{Const.} \notag \\
& = -\frac{T_0}{\theta} -r\log(\theta) + \text{Const.} \label{logL-type2}
\end{align}\]





Maximum likelihood estimator \[
\frac{\partial \ell(\theta)}{\partial\theta}\bigg\vert_{\theta = \hat\theta} =0 \;\;\Rightarrow\;\; {\color{purple}\hat\theta = (1/r)\Big[\sum_{i=1}^r t_{(i)} + (n-r) t_{(r)} \Big]}
\]

Observed information matrix \[
I(\hat\theta) = \frac{-\partial^2 \ell(\theta)}{\partial\theta^2}\bigg\vert_{\theta = \hat\theta} = \frac{r}{\hat\theta^2}
\]



\((1-\alpha)100\%\) CI for \(\theta\) (by Normal approximation) \[\begin{align}\label{ci_norm_theta}
\hat\theta \pm z_{1-\alpha/2} \Big[I(\hat\theta)\Big]^{-1/2}
\end{align}\]



Exact confidence interval for \(\theta\) can be derived for uncensored and Type II censored samples, define \[\begin{align*}
W_1 & = nt_{(1)} \\
W_2 & = (n-1)\big(t_{(2)} - t_{(1)}\big) \\
\vdots & \\
W_r & = (n-r +1)\big(t_{(r)} - t_{(r-1)}\big)
\end{align*}\]
In general \[
W_i = (n - i + 1) \big(t_{(i)} - t_{(i-1)}\big) \;\;i=1, \ldots, r
\]



It can be shown that \[
\sum_{i=1}^r W_i = \sum_{i=1}^r t_{(i)} + (n-r) t_{(r)} = T_0
\tag{4.1}\]




The joint distribution of \(W_1 = g_1(t_{(1)}, \ldots, t_{(r)}), \ldots, W_r=g_r(t_{(1)}, \ldots, t_{(r)})\) is: \[
f_W(w_1, \ldots, w_r)  = f_T\big(g_1^{-1}(w_1, \ldots, w_r), \ldots, g_r^{-1}(w_1, \ldots, w_r)\big) \times\,\big\vert J\big\vert
\] where \[
\begin{aligned}
J &= \frac{\partial\big(g_1^{-1}(w_1, \ldots, w_r), \ldots, g_r^{-1}(w_1, \ldots, w_r)\big)}{\partial(w_1, \ldots, w_r)} \\[.5em]
& = \begin{bmatrix}
\frac{\partial g_1^{-1}(w_1, \ldots, w_r)}{\partial w_1} &\frac{\partial g_2^{-1}(w_1, \ldots, w_r)}{\partial w_1} & \cdots & \frac{\partial g_r^{-1}(w_1, \ldots, w_r)}{\partial w_1} \\[.4em]
\frac{\partial g_1^{-1}(w_1, \ldots, w_r)}{\partial w_2} &\frac{\partial g_2^{-1}(w_1, \ldots, w_r)}{\partial w_2} & \cdots & \frac{\partial g_r^{-1}(w_1, \ldots, w_r)}{\partial w_2} \\[.2em]
\vdots & \vdots & \ddots & \vdots \\
\frac{\partial g_1^{-1}(w_1, \ldots, w_r)}{\partial w_r} &\frac{\partial g_2^{-1}(w_1, \ldots, w_r)}{\partial w_r} & \cdots & \frac{\partial g_r^{-1}(w_1, \ldots, w_r)}{\partial w_r}
\end{bmatrix}
\end{aligned}
\]



\[
\begin{aligned}
w_1 &= g_1(t_{(1)}, \ldots, t_{(r)}) = nt_{(1)} \;\;\Rightarrow \;\; t_{(1)} = g_1^{-1}(w_1, \ldots, w_r) = \frac{w_1}{n} \\
w_2 &= g_2(t_{(1)}, \ldots, t_{(r)}) = (n-1)(t_{(2)}-t_{(1)}) \\
& \Rightarrow \; t_{(2)} = g_2^{-1}(w_1, \ldots, w_r) = \frac{w_2}{n-1} + \frac{w_1}{n} \\
\vdots & \\
w_r &= g_r(t_{(1)}, \ldots, t_{(r)}) = (n-r +1)(t_{(r)}-t_{(r-1)}) \\
& \Rightarrow \; t_{(r)} = g_r^{-1}(w_1, \ldots, w_r) = \frac{w_r}{n-r+1} +\cdots + \frac{w_2}{n-1} + \frac{w_1}{n}
\end{aligned}
\]

\[
\begin{aligned}
J  & = \begin{bmatrix}
\frac{\partial g_1^{-1}(w_1, \ldots, w_r)}{\partial w_1} &\frac{\partial g_2^{-1}(w_1, \ldots, w_r)}{\partial w_1} & \cdots & \frac{\partial g_r^{-1}(w_1, \ldots, w_r)}{\partial w_1} \\[.4em]
\frac{\partial g_1^{-1}(w_1, \ldots, w_r)}{\partial w_2} &\frac{\partial g_2^{-1}(w_1, \ldots, w_r)}{\partial w_2} & \cdots & \frac{\partial g_r^{-1}(w_1, \ldots, w_r)}{\partial w_2} \\[.2em]
\vdots & \vdots & \ddots & \vdots \\
\frac{\partial g_1^{-1}(w_1, \ldots, w_r)}{\partial w_r} &\frac{\partial g_2^{-1}(w_1, \ldots, w_r)}{\partial w_r} & \cdots & \frac{\partial g_r^{-1}(w_1, \ldots, w_r)}{\partial w_r}
\end{bmatrix} \\[.25em]
& = \begin{bmatrix}
\frac{1}{n} & \frac{1}{n} & \cdots & \frac{1}{n}\\[.3em]
0& \frac{1}{n-1} & \cdots & \frac{1}{n-1}  \\
\vdots & \vdots & \ddots & \vdots \\
0 & 0 & \cdots & \frac{1}{n-r+1} \\
\end{bmatrix}
\end{aligned}
\]

We can write \[\begin{align}
\big\vert J \big\vert = \frac{1}{n\cdot (n-1)\cdots (n-r+1)} = \frac{(n-r)!}{n!}
\end{align}\]





The joint distribution of \(W_1 = g_1(t_{(1)}, \ldots, t_{(r)}), \ldots, W_r=g_r(t_{(1)}, \ldots, t_{(r)})\) is \[\begin{align}
f_W(w_1, \ldots, w_r)  &= f_T\big(g_1^{-1}(w_1, \ldots, w_r), \ldots, g_r^{-1}(w_1, \ldots, w_r)\big)\big\vert J\big\vert \notag \\[.25em]
& = \frac{n!}{(n-r)!}\,\frac{1}{\theta^r} \;e^{-\frac{1}{\theta}\big\{\sum_i g_i^{-1}(w_i) + (n-r)g_r^{-1}(w_r)\big\}} \frac{(n-r)!}{n!}\notag \\[.25em]
& = {\color{purple}\frac{1}{\theta^r}\;e^{-\sum_i w_i/\theta}} \label{eq-joint-W}
\end{align}\]

Using Equation 4.1




Equation \(\ref{eq-joint-W}\) shows that


\(W_1, \ldots, W_r\) are independent and \({\color{purple}W_i\sim \text{Exp}(\theta)}\)






Since \(W_i\)’ are independent and \(W_i\sim\text{Exp}(\theta)\), so \[
T_0 = \sum_i W_i = \sum_i t_{(i)} + (n-r)t_{(r)}
\] follows a gamma distribution with shape parameter \(r\) and scale parameter \(\theta\)
Then using the relationship between gamma and chi-square distribution \[
\frac{2T_0}{\theta} \sim  \chi^2_{(2r)}
\]




Moment generating functions for different distributions \[
\begin{aligned}
M_X(t) & = E\big[e^{tX}\big]\\
&= \begin{cases}
\frac{1}{1-\theta t} &\text{for $X\sim\text{Exp}(\theta)$} \\[.5em]
\Big(\frac{1}{1-\theta t}\Big)^r &\text{for $X\sim\text{Gamma}(r, \theta)$} \\[.5em]
\Big(\frac{1}{1-2t}\Big)^{r/2} &\text{for $X\sim\chi^2_{(r)}$}
\end{cases}
\end{aligned}
\]





Since \(\frac{2T_0}{\theta} \sim  \chi^2_{(2r)}\), we can write \[
P\bigg(\chi^2_{(2r), \,\alpha/2} \leq \frac{2T_0}{\theta}\leq \chi^2_{(2r), \,1-\alpha/2}\bigg) = 1-\alpha
\]


\(\chi^2_{(2r), \,p}\;\rightarrow\) \(p\)th quantile of \(\chi^2_{(2r)}\) distribution


\((1-\alpha)100\%\) exact confidence interval for \(\theta\) \[\begin{align}
\frac{2T_0}{\chi^2_{(2r), \,1-\alpha/2}}\leq \theta \leq \frac{2T_0}{\chi^2_{(2r), \,\alpha/2}}\label{LRT-ci-theta}
\end{align}\]


